jest.mock('embla-carousel-autoplay', () => ({
  __esModule: true,
  default: autoplayFactory
}));

const slides = Array.from({ length: 5 }, (_, index) => (
  <div key={`slide-${index}`} data-testid={`slide-${index}`}>
    Slide {index + 1}
  </div>
));

const renderCarousel = (
  props: Partial<CarouselProps> = {},
  customChildren: React.ReactNode = slides
): RenderResult =>
  render(
    <Carousel ariaLabel="Stories" {...props}>
      {customChildren}
    </Carousel>
  );

const ContextInvoker: React.FC<{
  onInvoke: (context: ReturnType<typeof useCarouselContext>) => void;
}> = ({ onInvoke }) => {
  const context = useCarouselContext();

  React.useEffect(() => {
    onInvoke(context);
  }, [context, onInvoke]);

  return null;
};

beforeEach(() => {
  jest.clearAllMocks();
  resetEmblaConfig();
  document.dir = 'ltr';
});

describe('Carousel', () => {
  it('renders a region with the provided accessible name', () => {
    renderCarousel();
    const region = screen.getByRole('region', { name: 'Stories' });
    expect(region).toBeInTheDocument();
  });

  it('renders the Embla container track', () => {
    renderCarousel();
    const region = screen.getByRole('region', { name: 'Stories' });
    const containerFound = Boolean(region.querySelector('.embla__container'));
    expect(containerFound).toBe(true);
  });

  it('omits indicators when showIndicators is false', () => {
    renderCarousel({ showIndicators: false });
    const indicator = screen.queryByRole('button', { name: /Go to slide/ });
    expect(indicator).toBeNull();
  });

  it('invokes Embla scrollTo when activating an indicator with Enter', async () => {
    renderCarousel();
    const buttons = screen.getAllByRole('button', { name: /Go to slide/ });
    const user = userEvent.setup();
    buttons[1].focus();
    await user.keyboard('{Enter}');
    const lastCall = currentEmblaControl.api.scrollTo.mock.calls.at(-1)?.[0];
    expect(lastCall).toBe(1);
  });

  it('activates an indicator when Space key is pressed', async () => {
    renderCarousel();
    const buttons = screen.getAllByRole('button', { name: /Go to slide/ });
    const user = userEvent.setup();
    buttons[2].focus();
    await user.keyboard('{Space}');
    currentEmblaControl.updateSelected(2);
    act(() => {
      currentEmblaControl.emit('select');
    });
    const ariaState = buttons.map(button => button.getAttribute('aria-current') === 'true');
    expect(ariaState).toEqual([false, false, true, false, false]);
  });

  it('marks the selected indicator with aria-current once Embla reports the index', () => {
    renderCarousel();
    currentEmblaControl.updateSelected(1);
    act(() => {
      currentEmblaControl.emit('select');
    });
    const buttons = screen.getAllByRole('button', { name: /Go to slide/ });
    expect(buttons[1].getAttribute('aria-current')).toBe('true');
  });

  it('forwarded context prev/next/goTo call the matching Embla methods', () => {
    renderCarousel(
      {
        autoPlay: false
      },
      <>
        {slides}
        <ContextInvoker
          onInvoke={ctx => {
            ctx.prev();
            ctx.next();
            ctx.goTo(2);
          }}
        />
      </>
    );
    const callSummary = {
      prev: currentEmblaControl.api.scrollPrev.mock.calls.length,
      next: currentEmblaControl.api.scrollNext.mock.calls.length,
      goTo: currentEmblaControl.api.scrollTo.mock.calls.at(-1)?.[0]
    };
    expect(callSummary).toEqual({ prev: 1, next: 1, goTo: 2 });
  });

  it('syncs the exposed currentIndex with Embla selected snaps', () => {
    const IndexProbe: React.FC = () => {
      const context = useCarouselContext();
      return <div data-testid="carousel-index">{context.currentIndex}</div>;
    };

    renderCarousel(
      {},
      (
        <>
          {slides}
          <IndexProbe />
        </>
      )
    );

    currentEmblaControl.updateSelected(2);
    act(() => {
      currentEmblaControl.emit('select');
    });
    expect(screen.getByTestId('carousel-index').textContent).toBe('2');
  });

  it('updates active indicator when the currentIndex prop changes', () => {
    const view = render(
      <Carousel ariaLabel="Stories" showIndicators currentIndex={1}>
        {slides}
      </Carousel>
    );

    const readState = () =>
      screen
        .getAllByRole('button', { name: /Go to slide/ })
        .map(button => button.getAttribute('aria-current') === 'true');

    const initialState = readState();

    view.rerender(
      <Carousel ariaLabel="Stories" showIndicators currentIndex={3}>
        {slides}
      </Carousel>
    );

    const finalState = readState();

    expect({ initial: initialState, final: finalState }).toEqual({
      initial: [false, true, false, false, false],
      final: [false, false, false, true, false]
    });
  });

  it('adds the dragging state class on pointerDown', () => {
    renderCarousel();
    act(() => {
      currentEmblaControl.emit('pointerDown');
    });
    const region = screen.getByRole('region', { name: 'Stories' });
    expect(region.className.includes('[--carousel-dragging:1]')).toBe(true);
  });

  it('removes the dragging state class after pointerUp', () => {
    renderCarousel();
    act(() => {
      currentEmblaControl.emit('pointerDown');
      currentEmblaControl.emit('pointerUp');
    });
    const region = screen.getByRole('region', { name: 'Stories' });
    expect(region.className.includes('[--carousel-dragging:1]')).toBe(false);
  });

  it('sets the edge start flag when Embla cannot scroll backward and loop is false', () => {
    renderCarousel({ loop: false });
    currentEmblaControl.setAvailability({ canPrev: false, canNext: true });
    act(() => {
      currentEmblaControl.emit('select');
    });
    const region = screen.getByRole('region', { name: 'Stories' });
    expect(region.className.includes('[--edge-start:1]')).toBe(true);
  });

  it('sets the edge end flag when Embla cannot scroll forward and loop is false', () => {
    renderCarousel({ loop: false });
    currentEmblaControl.setAvailability({ canPrev: true, canNext: false });
    act(() => {
      currentEmblaControl.emit('select');
    });
    const region = screen.getByRole('region', { name: 'Stories' });
    expect(region.className.includes('[--edge-end:1]')).toBe(true);
  });

  it('applies the rtl flag when the document direction is rtl', () => {
    document.dir = 'rtl';
    renderCarousel();
    const region = screen.getByRole('region', { name: 'Stories' });
    expect(region.className.includes('[direction:rtl]')).toBe(true);
  });

  it('configures autoplay with playOnInit=false when prefers-reduced-motion matches', () => {
    const originalMatchMedia = window.matchMedia;
    window.matchMedia = jest.fn().mockReturnValue({
      matches: true,
      media: '(prefers-reduced-motion: reduce)',
      onchange: null,
      addEventListener: jest.fn(),
      removeEventListener: jest.fn(),
      addListener: jest.fn(),
      removeListener: jest.fn(),
      dispatchEvent: jest.fn()
    }) as unknown as typeof window.matchMedia;

    renderCarousel({ autoPlay: true, respectReducedMotion: true });
    window.matchMedia = originalMatchMedia;
    const playOnInit = autoplayFactory.mock.calls.at(-1)?.[0]?.playOnInit;
    expect(playOnInit).toBe(false);
  });

  it('manual stop and play surface onAutoPlayChange callbacks once each', () => {
    const handleAutoPlayChange = jest.fn();

    renderCarousel(
      { autoPlay: true, onAutoPlayChange: handleAutoPlayChange },
      (
        <>
          {slides}
          <ContextInvoker
            onInvoke={ctx => {
              ctx.autoPlay?.stop();
              ctx.autoPlay?.play();
            }}
          />
        </>
      )
    );

    const calls = handleAutoPlayChange.mock.calls.map(([value]) => value);
    expect(calls).toEqual([false, true]);
  });

  it('relays autoplay plugin play/stop events to onAutoPlayChange in order', () => {
    const handleAutoPlayChange = jest.fn();
    renderCarousel({ autoPlay: true, onAutoPlayChange: handleAutoPlayChange });
    const playHandlers = currentEmblaControl.getHandlers('autoplay:play') ?? [];
    const stopHandlers = currentEmblaControl.getHandlers('autoplay:stop') ?? [];
    playHandlers.forEach(handler => handler(currentEmblaControl.api));
    stopHandlers.forEach(handler => handler(currentEmblaControl.api));
    const calls = handleAutoPlayChange.mock.calls.map(([value]) => value);
    expect(calls).toEqual([true, false]);
  });

  it('fires onInViewChange only when the visibility set changes', () => {
    const handleInViewChange = jest.fn();
    renderCarousel({ onInViewChange: handleInViewChange });
    currentEmblaControl.setSlidesInView([0, 1]);
    act(() => {
      currentEmblaControl.emit('slidesInView');
      currentEmblaControl.emit('slidesInView');
    });
    expect(handleInViewChange.mock.calls).toEqual([[ [0, 1] ]]);
  });
});
